final:
module top_module (
    input [1:0] k,
    output reg u
);
  wire [1:0] _tap_k = k & {2{1'b1}};


    always @(*) begin
        case (k)
            2'b00: u = 0;
            2'b01: u = 0;
            2'b10: u = 1;
            2'b11: u = 1;
            default: u = 0; // Default case
        endcase
    end
endmodule
